// === TEST CASES ===
// TC1: { roomType:"kitchen", roomSize:"small", finishLevel:"budget", includeAppliances:false, includeLabor:true } → { total:10000, breakdown:{ baseTotal:10000, materialCost:6000, laborCost:4000, applianceCost:0 } }
// TC2: { roomType:"kitchen", roomSize:"small", finishLevel:"budget", includeAppliances:false, includeLabor:false } → { total:6000, breakdown:{ baseTotal:10000, materialCost:6000, laborCost:0, applianceCost:0 } }
// TC3: { roomType:"kitchen", roomSize:"medium", finishLevel:"mid", includeAppliances:true, includeLabor:true } → { total:40000, breakdown:{ baseTotal:35000, materialCost:21000, laborCost:14000, applianceCost:5000 } }
// TC4: { roomType:"bathroom", roomSize:"large", finishLevel:"high_end", includeAppliances:true, includeLabor:true } → { total:46500, breakdown:{ baseTotal:45000, materialCost:27000, laborCost:18000, applianceCost:1500 } }
// TC5: { roomType:"basement", roomSize:"small", finishLevel:"mid", includeAppliances:false, includeLabor:true } → { total:30000, breakdown:{ baseTotal:30000, materialCost:18000, laborCost:12000, applianceCost:0 } }
// TC6: { roomType:"garage", roomSize:"small", finishLevel:"budget", includeAppliances:false, includeLabor:true } → { error:"Invalid room type" }
// TC7: { roomType:"kitchen", roomSize:"tiny", finishLevel:"budget", includeAppliances:false, includeLabor:true } → { error:"Invalid room size" }
// TC8: { roomSize:"small", finishLevel:"budget", includeAppliances:false, includeLabor:true } → { error:"Missing required parameter: roomType" }
// TC9: { roomType:"kitchen", roomSize:"small", finishLevel:"budget", includeAppliances:"true", includeLabor:true } → { error:"includeAppliances must be boolean" }
// TC10: { roomType:"kitchen", roomSize:"small", finishLevel:"budget", includeAppliances:false, includeLabor:1 } → { error:"includeLabor must be boolean" }
// TC11: { roomType:"bathroom", roomSize:"medium", finishLevel:"budget", includeAppliances:false, includeLabor:false } → { total:4800, breakdown:{ baseTotal:8000, materialCost:4800, laborCost:0, applianceCost:0 } }
// TC12: { roomType:"basement", roomSize:"large", finishLevel:"high_end", includeAppliances:false, includeLabor:false } → { total:72000, breakdown:{ baseTotal:120000, materialCost:72000, laborCost:0, applianceCost:0 } }
// TC13: { roomType:"kitchen", roomSize:"small", finishLevel:"high_end", includeAppliances:false, includeLabor:true } → { total:35000, breakdown:{ baseTotal:35000, materialCost:21000, laborCost:14000, applianceCost:0 } }
// TC14: { roomType:"Kitchen", roomSize:"Medium", finishLevel:"Mid", includeAppliances:false, includeLabor:true } → { total:35000, breakdown:{ baseTotal:35000, materialCost:21000, laborCost:14000, applianceCost:0 } } // case-insensitive
// TC15: { roomType:"basement", roomSize:"small", finishLevel:"High_End", includeAppliances:false, includeLabor:true } → { total:50000, breakdown:{ baseTotal:50000, materialCost:30000, laborCost:20000, applianceCost:0 } } // underscores preserved
// TC16: { roomType:"bathroom", roomSize:"small", finishLevel:"high_end", includeAppliances:false } → { error:"Missing required parameter: includeLabor" }
// TC17: { } → { error:"Missing required parameter: roomType" }
// TC18: { roomType:"  Kitchen  ", roomSize:"large", finishLevel:"mid", includeAppliances:true, includeLabor:false } → { total:34500, breakdown:{ baseTotal:55000, materialCost:33000, laborCost:0, applianceCost:5000 } } // trimmed whitespace
// TC19: { roomType:"basement", roomSize:"large", finishLevel:"mid", includeAppliances:false, includeLabor:true } → { total:80000, breakdown:{ baseTotal:80000, materialCost:48000, laborCost:32000, applianceCost:0 } }
// TC20: { roomType:"basement", roomSize:"small", finishLevel:"budget", includeAppliances:false, includeLabor:false } → { total:9000, breakdown:{ baseTotal:15000, materialCost:9000, laborCost:0, applianceCost:0 } }
// TC21: { roomType:"kitchen", roomSize:"large", finishLevel:"high_end", includeAppliances:true, includeLabor:false } → { total:53000, breakdown:{ baseTotal:80000, materialCost:48000, laborCost:0, applianceCost:5000 } }
// TC22: { roomType:"bathroom", roomSize:"small", finishLevel:"high_end", includeAppliances:true, includeLabor:false } → { total:13500, breakdown:{ baseTotal:20000, materialCost:12000, laborCost:0, applianceCost:1500 } }

const calculator = {
  COST_MATRIX: {
    kitchen: {
      small: { budget: 10000, mid: 20000, high_end: 35000 },
      medium: { budget: 20000, mid: 35000, high_end: 55000 },
      large: { budget: 35000, mid: 55000, high_end: 80000 }
    },
    bathroom: {
      small: { budget: 5000, mid: 10000, high_end: 20000 },
      medium: { budget: 8000, mid: 15000, high_end: 30000 },
      large: { budget: 12000, mid: 25000, high_end: 45000 }
    },
    basement: {
      small: { budget: 15000, mid: 30000, high_end: 50000 },
      medium: { budget: 30000, mid: 50000, high_end: 80000 },
      large: { budget: 50000, mid: 80000, high_end: 120000 }
    }
  },
  APPLIANCE_COST: { kitchen: 5000, bathroom: 1500, basement: 3000 },
  LABOR_RATIO: 0.4,

  calculate(inputs) {
    const err = this.validate(inputs);
    if (err) return err;

    const roomType = String(inputs.roomType).trim().toLowerCase();
    const roomSize = String(inputs.roomSize).trim().toLowerCase();
    const finishLevel = String(inputs.finishLevel).trim().toLowerCase();
    const includeAppliances = inputs.includeAppliances;
    const includeLabor = inputs.includeLabor;

    const baseTotal = this.COST_MATRIX[roomType][roomSize][finishLevel];
    const laborCost = baseTotal * this.LABOR_RATIO;
    const materialCost = baseTotal - laborCost;
    const applianceCost = includeAppliances ? this.APPLIANCE_COST[roomType] : 0;

    const appliedLabor = includeLabor ? laborCost : 0;
    const total = materialCost + appliedLabor + applianceCost;

    return {
      total,
      breakdown: {
        baseTotal,
        materialCost,
        laborCost: appliedLabor,
        applianceCost,
      }
    };
  },

  validate(inputs) {
    if (inputs == null) return { error: "No inputs provided" };

    // --- roomType ---
    const rawRoom = inputs.roomType;
    if (rawRoom === undefined || rawRoom === null || String(rawRoom).trim() === '') {
      return { error: "Missing required parameter: roomType" };
    }
    const roomType = String(rawRoom).trim().toLowerCase();
    if (!['kitchen', 'bathroom', 'basement'].includes(roomType)) {
      return { error: "Invalid room type" };
    }

    // --- roomSize ---
    const rawSize = inputs.roomSize;
    if (rawSize === undefined || rawSize === null || String(rawSize).trim() === '') {
      return { error: "Missing required parameter: roomSize" };
    }
    const roomSize = String(rawSize).trim().toLowerCase();
    if (!['small', 'medium', 'large'].includes(roomSize)) {
      return { error: "Invalid room size" };
    }

    // --- finishLevel ---
    const rawFinish = inputs.finishLevel;
    if (rawFinish === undefined || rawFinish === null || String(rawFinish).trim() === '') {
      return { error: "Missing required parameter: finishLevel" };
    }
    const finishLevel = String(rawFinish).trim().toLowerCase();
    if (!['budget', 'mid', 'high_end'].includes(finishLevel)) {
      return { error: "Invalid finish level" };
    }

    // --- includeAppliances ---
    const rawAppliances = inputs.includeAppliances;
    if (typeof rawAppliances !== 'boolean') {
      return { error: "includeAppliances must be boolean" };
    }

    // --- includeLabor ---
    const rawLabor = inputs.includeLabor;
    if (typeof rawLabor !== 'boolean') {
      return { error: "includeLabor must be boolean" };
    }

    return null; // valid
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  }
};

const CALC_PARAMS = [
  {
    name: 'roomType',
    label: 'Room Type',
    type: 'select',
    options: [
      ['kitchen', 'Kitchen'],
      ['bathroom', 'Bathroom'],
      ['basement', 'Basement']
    ]
  },
  {
    name: 'roomSize',
    label: 'Room Size',
    type: 'select',
    options: [
      ['small', 'Small'],
      ['medium', 'Medium'],
      ['large', 'Large']
    ]
  },
  {
    name: 'finishLevel',
    label: 'Finish Level',
    type: 'select',
    options: [
      ['budget', 'Budget'],
      ['mid', 'Mid'],
      ['high_end', 'High-end']
    ]
  },
  {
    name: 'includeAppliances',
    label: 'Include appliances?',
    type: 'checkbox'
  },
  {
    name: 'includeLabor',
    label: 'Include labor?',
    type: 'checkbox'
  }
];
